import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"碎股单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/odd-lot.md","filePath":"zh-CN/stock-trading/order-types/odd-lot.md"}'),o={name:"stock-trading/order-types/odd-lot.md"};function i(h,a,d,n,s,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="碎股单" tabindex="-1">碎股单 <a class="header-anchor" href="#碎股单" aria-label="Permalink to &quot;碎股单&quot;">​</a></h1><p>港股和美股碎股交易定义、交易时间、订单规则、收费及转仓规则。</p><h2 id="什么是碎股" tabindex="-1">什么是碎股 <a class="header-anchor" href="#什么是碎股" aria-label="Permalink to &quot;什么是碎股&quot;">​</a></h2><p>港股一般以一手为买卖单位，每手股票数量根据股价不同可能为 100 股、500 股、1000 股或 2000 股以上不等。「碎股」指少于完整一手的证券数量。</p><p>美股一般以一股为买卖单位，「碎股」指少于 1 股的证券数量（如 0.5 股）。</p><hr><h2 id="港股碎股交易" tabindex="-1">港股碎股交易 <a class="header-anchor" href="#港股碎股交易" aria-label="Permalink to &quot;港股碎股交易&quot;">​</a></h2><h3 id="下单方式" tabindex="-1">下单方式 <a class="header-anchor" href="#下单方式" aria-label="Permalink to &quot;下单方式&quot;">​</a></h3><p>长桥 App - 资产 - 交易大厅，选择股票及买卖方向后，在类型中选择「碎股单」，输入价格及数量下单。</p><h3 id="交易时间" tabindex="-1">交易时间 <a class="header-anchor" href="#交易时间" aria-label="Permalink to &quot;交易时间&quot;">​</a></h3><p>碎股只能在港股持续交易时段交易（交易日 09:30 - 12:00、13:00 - 16:00），不设早市竞价及收市竞价时段。</p><h3 id="订单规则" tabindex="-1">订单规则 <a class="header-anchor" href="#订单规则" aria-label="Permalink to &quot;订单规则&quot;">​</a></h3><ul><li>仅支持「碎股单」订单类型，不设市价单及条件单</li><li>下单后不能修改订单，但可以撤单</li><li>碎股及整手股票需分别下单，碎股下单股数必须少于一手数量</li><li>支持订单有效期：当日有效</li></ul><h3 id="收费" tabindex="-1">收费 <a class="header-anchor" href="#收费" aria-label="Permalink to &quot;收费&quot;">​</a></h3><p>碎股交易的收费与整手交易收费相同。</p><h3 id="成交与价格" tabindex="-1">成交与价格 <a class="header-anchor" href="#成交与价格" aria-label="Permalink to &quot;成交与价格&quot;">​</a></h3><p>碎股市场流通量较少，可能因没有匹配到买卖对手而未能成交。买入价格通常比整手高（一般至少相差 5 个价位），建议输入比市价略高的买入价以增加成交机会；卖出同理，价格通常比整手低，建议输入比市价略低的卖出价。</p><hr><h2 id="美股碎股交易" tabindex="-1">美股碎股交易 <a class="header-anchor" href="#美股碎股交易" aria-label="Permalink to &quot;美股碎股交易&quot;">​</a></h2><h3 id="支持标的" tabindex="-1">支持标的 <a class="header-anchor" href="#支持标的" aria-label="Permalink to &quot;支持标的&quot;">​</a></h3><p>可通过长桥 App 市场 - 分类榜查找支持碎股交易的标的，个股详情页会展示碎股图标。</p><h3 id="下单方式-1" tabindex="-1">下单方式 <a class="header-anchor" href="#下单方式-1" aria-label="Permalink to &quot;下单方式&quot;">​</a></h3><ul><li>直接输入小数数量交易（可接受小数点后 4 位）</li><li>选择金额交易并输入金额，系统自动根据当前股价转换为对应股份数量</li></ul><h3 id="交易时间-1" tabindex="-1">交易时间 <a class="header-anchor" href="#交易时间-1" aria-label="Permalink to &quot;交易时间&quot;">​</a></h3><p>美股碎股仅支持盘中交易：09:30 - 16:00（美东时间）。半日市为 09:30 - 13:00（美东时间）。</p><h3 id="订单规则-1" tabindex="-1">订单规则 <a class="header-anchor" href="#订单规则-1" aria-label="Permalink to &quot;订单规则&quot;">​</a></h3><ul><li>支持限价单及市价单，暂不支持条件单或网格订单</li><li>暂不支持改单，需先撤单后重新下单</li><li>碎股交易金额最低 1 美元</li></ul><h3 id="收费-1" tabindex="-1">收费 <a class="header-anchor" href="#收费-1" aria-label="Permalink to &quot;收费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>佣金</th><th>平台使用费</th></tr></thead><tbody><tr><td>单笔成交数量 &lt; 1 股</td><td>免费</td><td>0.99% × 交易金额，每笔最高 0.99 美元</td></tr><tr><td>单笔成交数量 ≥ 1 股</td><td>按照美股收费规则正常收取</td><td></td></tr></tbody></table><h3 id="融资与做空" tabindex="-1">融资与做空 <a class="header-anchor" href="#融资与做空" aria-label="Permalink to &quot;融资与做空&quot;">​</a></h3><p>碎股不允许做空。碎股支持统一购买力，融资利率与整股相同。</p><h3 id="公司行动" tabindex="-1">公司行动 <a class="header-anchor" href="#公司行动" aria-label="Permalink to &quot;公司行动&quot;">​</a></h3><p>支持分红派息、股票拆分等强制类公司行动，不支持供股、邀约等自愿性公司行动。</p><p>如遇拆合股，客户可能收到碎股（如某股票 10 合 1，合股前持有 5 股，合股后将收到 0.5 股）。</p><hr><h2 id="碎股转仓" tabindex="-1">碎股转仓 <a class="header-anchor" href="#碎股转仓" aria-label="Permalink to &quot;碎股转仓&quot;">​</a></h2><p>长桥支持碎股转入及转出。</p>',37)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
